#include<iostream>
using namespace std;
class Solution {
public:
    bool solve(vector<int>& arr) {
        if (arr.empty()) return -1;
        int element = arr.front();
        arr.erase(arr.begin());
        return element;
    }
};
int main() {
    int n; cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    Solution s;
    cout << s.solve(arr) << endl;
    return 0;
}
